SELECT COUNT(*)
FROM review
WHERE deal_id = #{dealId} AND writer_id = #{writerId}

SELECT
    m.nickname AS buyerNickname,
    r.rating AS rating,
    r.content AS reviewText,
    r.created_at AS reviewDate
FROM review r 
INNER JOIN member m ON m.id = r.writer_id
WHERE r.target_id = #{sellerId}
ORDER BY r.created_at ${pageRequest.order}
LIMIT #{pageRequest.size}
OFFSET #{pageRequest.offset}

SELECT COUNT(*)
FROM review r
WHERE r.target_id = #{sellerId}
